// Themen-Pool für den Scheduler
// Beim Webhook-Trigger kommt das Thema aus dem Request-Body
const isWebhook = $input.first().json.body !== undefined;

let topic, language;

if (isWebhook) {
  // Webhook: { topic: 'Claude source leak', lang: 'de' }
  topic = $input.first().json.body.topic;
  language = $input.first().json.body.lang || 'de';
} else {
  // Scheduler: Thema aus aktuellem Tech-Kontext
  const topics = [
    'PowerShell Best Practices für Windows Server Admins 2025',
    'Docker Security Hardening – Produktionsreife Container',
    'Cloudflare Workers vs. traditionelle Server für Webhooks',
    'AI in der IT-Administration – sinnvolle Anwendungsfälle',
    'Hyper-V Cluster Performance-Optimierung',
    'Self-Hosted Monitoring Stack mit Netdata und Gotify',
    'DNS-Architektur für On-Premises Umgebungen',
    'n8n für IT-Automatisierung – Praxisbeispiele'
  ];
  topic = topics[Math.floor(Math.random() * topics.length)];
  language = 'de';
}

return [{ json: { topic, language } }];

const raw = $input.first().json.content[0].text;

// Markdown aus dem ```markdown ... ``` Block extrahieren
let markdown = raw;
const fenceMatch = raw.match(/```markdown\n([\s\S]+?)\n```/);
if (fenceMatch) {
  markdown = fenceMatch[1];
}

// Slug aus dem Titel generieren
const titleMatch = markdown.match(/^title:\s*"([^"]+)"/m);
const title = titleMatch ? titleMatch[1] : 'neuer-blog-post';

const slug = title
  .toLowerCase()
  .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss')
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .substring(0, 60);

const filename = `${slug}.md`;

// Base64-kodieren für die GitHub API
const contentB64 = Buffer.from(markdown).toString('base64');

return [{ json: { filename, contentB64, markdown, slug } }];
